queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?realname WHERE {
  ?artists a :Artist .
  OPTIONAL { ?artists p:realName ?realname . }
  ?artists p:id ?id_in .
  FILTER NOT EXISTS { ?sub a :MusicAlbums . ?sub p:artistId ?id_in . ?sub p:releaseYear ?s_releaseyear . FILTER(xsd:double(?s_releaseyear) < 1995) }
}

